         int parameter_offset,
         fp *finavalu);

fp cam(fp timeinst,
       fp *initvalu,
       int initvalu_offset,
       fp *parameter,
       int parameter_offset,
       fp *finavalu,
       fp Ca);

void kernel_fin(fp *initvalu,
                int initvalu_offset_ecc,
                int initvalu_offset_Dyad,
                int initvalu_offset_SL,
                int initvalu_offset_Cyt,
                fp *parameter,
                fp *finavalu,
                fp JCaDyad,
                fp JCaSL,
                fp JCaCyt);

void master(fp timeinst,
            fp *initvalu,
            fp *parameter,
            fp *finavalu,
            fp *com)
{
    int i;

    int initvalu_offset_ecc = 0;
    int initvalu_offset_Dyad = 46;
    int initvalu_offset_SL = 61;
    int initvalu_offset_Cyt = 76;

    fp JCaDyad = 0.0f;
    fp JCaSL = 0.0f;
    fp JCaCyt = 0.0f;

#pragma omp parallel sections
    {
#pragma omp section
        {
            ecc(timeinst,
                initvalu,
                initvalu_offset_ecc,
                parameter,
                15,
                finavalu);
        }

#pragma omp section
        {
            fp CaDyad = initvalu[35] * 1e3f;
            JCaDyad = cam(timeinst,
                          initvalu,
                          initvalu_offset_Dyad,
                          parameter,
                          0,
                          finavalu,
                          CaDyad);
        }

#pragma omp section
        {
            fp CaSL = initvalu[36] * 1e3f;
            JCaSL = cam(timeinst,
                        initvalu,
                        initvalu_offset_SL,
                        parameter,
                        5,
                        finavalu,
                        CaSL);
        }

#pragma omp section
        {
            fp CaCyt = initvalu[37] * 1e3f;
            JCaCyt = cam(timeinst,
                         initvalu,
                         initvalu_offset_Cyt,
                         parameter,
                         10,
                         finavalu,
                         CaCyt);
        }
    }

    com[0] = JCaDyad;
    com[1] = JCaSL;
    com[2] = JCaCyt;

    kernel_fin(initvalu,
               initvalu_offset_ecc,
               initvalu_offset_Dyad,
               initvalu_offset_SL,
               initvalu_offset_Cyt,
               parameter,
               finavalu,
               com[0],
               com[1],
               com[2]);

    for (i = 0; i < EQUATIONS; i++) {
        if (isnan(finavalu[i]) == 1 || isinf(finavalu[i]) == 1) {
            finavalu[i] = 0.0001f;
        }
    }
}

